class DataRetentionService {
    private static final int DATA_RETENTION_PERIOD_IN_DAYS = 365;

    void purgeExpiredRecords(LocalDate asOfDate) {
        LocalDate retentionCutoffDate = asOfDate.minusDays(DATA_RETENTION_PERIOD_IN_DAYS);
        List<DataRecord> expiredRecords = recordRepository.findRecordsOlderThan(retentionCutoffDate);
        logger.info("Purging {} records older than {} days (cutoff: {})",
            expiredRecords.size(),
            DATA_RETENTION_PERIOD_IN_DAYS,
            retentionCutoffDate);
        recordRepository.deleteAll(expiredRecords);
    }
}
